import{_ as o,o as t,c as a,a3 as i}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Leads — Production Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Leads — Production Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/leads"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Leads — Production Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/leads"}]]},"headers":[],"relativePath":"deployment/leads.md","filePath":"deployment/leads.md","lastUpdated":1784926677000}'),s={name:"deployment/leads.md"};function d(l,e,r,n,c,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="leads-—-production-guide" tabindex="-1">Leads — Production Guide <a class="header-anchor" href="#leads-—-production-guide" aria-label="Permalink to &quot;Leads — Production Guide&quot;">​</a></h1><h2 id="licensing" tabindex="-1">Licensing <a class="header-anchor" href="#licensing" aria-label="Permalink to &quot;Licensing&quot;">​</a></h2><ul><li>Catalog slug: <code>leads</code></li><li>Default-included, non-billable for new workspaces</li><li>Deactivate via Central module subscription tools to revoke access without dropping data</li></ul><h2 id="bootstrap" tabindex="-1">Bootstrap <a class="header-anchor" href="#bootstrap" aria-label="Permalink to &quot;Bootstrap&quot;">​</a></h2><p>On workspace provision:</p><ol><li>Default modules installed (includes Leads)</li><li><code>LeadService::ensureDefaultStages()</code> / <code>LeadStageSeeder</code> seeds New → … → Won / Lost</li></ol><p>Existing workspaces without stages get stages lazily on first Leads API call.</p><h2 id="permissions-rollout" tabindex="-1">Permissions rollout <a class="header-anchor" href="#permissions-rollout" aria-label="Permalink to &quot;Permissions rollout&quot;">​</a></h2><p>New Leads permissions for <strong>existing</strong> workspaces must ship as an additive <strong>data migration</strong> using <code>TenantPermissionSynchronizer::grantMissingDefaultRolePermissions([...])</code> (same pattern as Communication Templates). Do <strong>not</strong> re-seed roles or rely on login/dashboard to repair RBAC.</p><p>Status migration maps legacy <code>open</code> → <code>active</code> and <code>won</code>/<code>lost</code> → <code>closed</code>. Column rename: <code>estimated_value</code> → <code>lead_value</code>.</p><p>Include <code>leads.manage_integrations</code> in the grant list for lead ingest integrations.</p><h2 id="queue-workers" tabindex="-1">Queue workers <a class="header-anchor" href="#queue-workers" aria-label="Permalink to &quot;Queue workers&quot;">​</a></h2><p>Lead imports run on the dedicated <code>imports</code> queue. Meta Lead Ads ingest uses <code>lead-ingest</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> queue:work</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --queue=lead-ingest,imports,emails,default</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sleep=1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tries=3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-time=3600</span></span></code></pre></div><p>Ensure at least one worker listens to <code>imports</code> and <code>lead-ingest</code>. Uploads use the configured <code>filesystems.uploads</code> disk (<code>public</code> locally / <code>s3</code> in production) under <code>imports/{tenant_uuid}/</code>.</p><h2 id="lead-ingest-webhooks" tabindex="-1">Lead ingest webhooks <a class="header-anchor" href="#lead-ingest-webhooks" aria-label="Permalink to &quot;Lead ingest webhooks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Notes</th></tr></thead><tbody><tr><td><code>POST /webhooks/leads/custom/{uuid}</code></td><td>Per-tenant Custom Webhook (HMAC or Bearer)</td></tr><tr><td><code>GET/POST /webhooks/leads/meta</code></td><td>Shared Meta Lead Ads ingress (signature + verify challenge)</td></tr></tbody></table><p>CSRF-exempt under <code>webhooks/leads/*</code>. Configure Meta App ID/secret/verify token via Central <code>PUT /api/central/v1/integrations/meta-lead-ads</code> or <code>META_LEAD_ADS_*</code> env.</p><h3 id="meta-production-gates-required-for-customer-pages" tabindex="-1">Meta production gates (required for customer Pages) <a class="header-anchor" href="#meta-production-gates-required-for-customer-pages" aria-label="Permalink to &quot;Meta production gates (required for customer Pages)&quot;">​</a></h3><p>Before enabling Meta Lead Ads for customer workspaces:</p><ol><li>Meta <strong>Business Verification</strong> completed for the platform app</li><li>Meta <strong>App Review</strong> approved for <code>leads_retrieval</code> + <code>pages_manage_metadata</code> (and related Page scopes)</li><li>App switched to <strong>Live Mode</strong></li><li>Webhook subscription field <code>leadgen</code> pointed at <code>https://{api}/webhooks/leads/meta</code> with the configured verify token</li><li>OAuth redirect URI registered: <code>https://{api}/api/oauth/leads/meta/callback</code></li><li>At least one worker consuming <code>lead-ingest</code></li><li>Smoke: Connect Meta → select Pages → submit a Lead Ad form → lead appears in workspace</li></ol><p>Without steps 1–3, only Meta test Apps / test users work.</p><h3 id="deploy-checklist-ingest" tabindex="-1">Deploy checklist (ingest) <a class="header-anchor" href="#deploy-checklist-ingest" aria-label="Permalink to &quot;Deploy checklist (ingest)&quot;">​</a></h3><ul><li>[ ] Migrate ingest tables + <code>leads.manage_integrations</code> permission grant</li><li>[ ] Queue worker includes <code>lead-ingest</code></li><li>[ ] <code>META_LEAD_ADS_*</code> (or Central settings) set for production</li><li>[ ] Custom webhook HMAC/Bearer smoke</li><li>[ ] Meta verify challenge + signed webhook smoke (sandbox)</li><li>[ ] Confirm deactivated <code>module:leads</code> rejects ingress</li></ul><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><ul><li>Platform audit events: <code>lead_created</code>, <code>lead_updated</code>, <code>lead_deleted</code>, <code>lead_assigned</code>, <code>lead_stage_changed</code>, <code>lead_note_added</code>, <code>lead_follow_up_*</code>, <code>lead_import_completed</code>, <code>lead_import_failed</code>, convert-related activity</li><li>Mail + database notifications: assignment, follow-up created, follow-up due/overdue (<code>crm:send-due-notifications</code> every 5 minutes)</li><li>Tenant mail settings with Central SMTP fallback</li></ul><h2 id="scheduled-jobs" tabindex="-1">Scheduled jobs <a class="header-anchor" href="#scheduled-jobs" aria-label="Permalink to &quot;Scheduled jobs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Cadence</th><th>Purpose</th></tr></thead><tbody><tr><td><code>crm:send-due-notifications</code></td><td>Every 5 minutes (<code>onOneServer</code>)</td><td>Idempotent due/overdue follow-up (and task) notifications</td></tr></tbody></table><p>Ensure the Laravel scheduler is running in production.</p><h2 id="deploy-checklist" tabindex="-1">Deploy checklist <a class="header-anchor" href="#deploy-checklist" aria-label="Permalink to &quot;Deploy checklist&quot;">​</a></h2><ol><li>Migrate lead tables + Sprint 2 enhance migration + <code>lead_assignment_histories</code> + <code>lead_imports</code></li><li>Deploy frontend (Kanban/table, KPIs, export, import wizard/history, convert stub, notifications)</li><li>Confirm <code>module:leads</code> + expanded permissions (including <code>leads.import</code>)</li><li>Confirm queue worker includes <code>imports</code></li><li>Smoke: register/login → Leads board → create → DnD stage (save) → export → import template → small CSV import → history download → convert stub</li></ol>',31)])])}const m=o(s,[["render",d]]);export{h as __pageData,m as default};
